import{_ as a,o as s,c as i,a0 as t}from"./chunks/framework.CWk8AOcY.js";const u=JSON.parse('{"title":"HTTPS & Domain Resolution","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/https-and-domain.md","filePath":"guide/https-and-domain.md"}'),o={name:"en/guide/https-and-domain.md"};function n(r,e,l,d,c,p){return s(),i("div",null,[...e[0]||(e[0]=[t(`<h1 id="https-domain-resolution" tabindex="-1">HTTPS &amp; Domain Resolution <a class="header-anchor" href="#https-domain-resolution" aria-label="Permalink to &quot;HTTPS &amp; Domain Resolution&quot;">​</a></h1><p>This guide explains how sandbox access domains work in Cube Sandbox and how to resolve common <strong>HTTPS certificate</strong> and <strong>DNS resolution</strong> issues.</p><blockquote><p><strong>Note:</strong> TLS configuration only affects how clients reach CubeProxy. <code>E2B_API_URL</code> always points to the <strong>Cube API Server</strong> (default port <code>3000</code>) — a separate component from CubeProxy.</p></blockquote><hr><h2 id="how-sandbox-domains-work" tabindex="-1">How Sandbox Domains Work <a class="header-anchor" href="#how-sandbox-domains-work" aria-label="Permalink to &quot;How Sandbox Domains Work&quot;">​</a></h2><p>When an E2B client accesses a sandbox, the domain name is <strong>dynamically generated</strong> using the following format:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;sandbox-service-port&gt;-&lt;sandboxId&gt;.&lt;domain&gt;</span></span></code></pre></div><p>For example:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>49983-1aa1fae8fb364edaa8203a7481995b4d.cube.app</span></span></code></pre></div><p>Where:</p><ul><li><code>sandbox-service-port</code>: the port your sandbox application listens on (e.g. <code>49999</code>)</li><li><code>sandboxId</code>: the unique sandbox ID</li><li><code>domain</code>: the base domain, defaults to <code>cube.app</code>, customizable via <code>--sandbox-domain</code></li></ul><p>Because the <code>sandboxId</code> part changes dynamically for every sandbox, <strong>the network environment where the E2B client runs must support wildcard DNS resolution</strong> — i.e., <code>*.&lt;domain&gt;</code> must resolve to the IP of the machine running CubeProxy.</p><h3 id="built-in-coredns-in-one-click-install-for-quick-start" tabindex="-1">Built-in CoreDNS in One-Click Install (for Quick Start) <a class="header-anchor" href="#built-in-coredns-in-one-click-install-for-quick-start" aria-label="Permalink to &quot;Built-in CoreDNS in One-Click Install (for Quick Start)&quot;">​</a></h3><p>The Cube one-click install script starts a <strong>CoreDNS</strong> service on the installation node that automatically handles wildcard resolution for <code>*.cube.app</code>. This lets you experience the full workflow on that machine without any extra DNS setup.</p><blockquote><p><strong>Note:</strong> The built-in CoreDNS is intended for local/quick-start use only — it is not suitable for production or multi-machine shared deployments.</p></blockquote><h3 id="production-custom-domain-your-own-dns" tabindex="-1">Production: Custom Domain + Your Own DNS <a class="header-anchor" href="#production-custom-domain-your-own-dns" aria-label="Permalink to &quot;Production: Custom Domain + Your Own DNS&quot;">​</a></h3><p>For production deployments, use your own domain and configure a wildcard DNS record:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>*.your.domain.com  →  &lt;IP of the node running CubeProxy&gt;</span></span></code></pre></div><p>Then tell the Cube API Server to use that domain at startup:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># CLI flag</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./cube-api</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --sandbox-domain</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> your.domain.com</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Or via environment variable</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> CUBE_API_SANDBOX_DOMAIN</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">your.domain.com</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./cube-api</span></span></code></pre></div><p>With this in place, the <code>domain</code> field in API responses will return <code>your.domain.com</code>, allowing the E2B SDK to correctly construct sandbox access URLs.</p><hr><h2 id="https-certificate-configuration" tabindex="-1">HTTPS Certificate Configuration <a class="header-anchor" href="#https-certificate-configuration" aria-label="Permalink to &quot;HTTPS Certificate Configuration&quot;">​</a></h2><p>CubeProxy serves both <strong>HTTPS (port 443) and HTTP (port 80)</strong> out of the box. The E2B SDK uses HTTPS by default. The one-click install pre-installs a <code>cube.app</code> test certificate so you can try HTTPS immediately.</p><p>To use a custom domain or production certificate, choose one of the options below:</p><h3 id="option-a-—-mkcert-local-dev-quick-setup" tabindex="-1">Option A — mkcert (Local Dev Quick Setup) <a class="header-anchor" href="#option-a-—-mkcert-local-dev-quick-setup" aria-label="Permalink to &quot;Option A — mkcert (Local Dev Quick Setup)&quot;">​</a></h3><p><code>mkcert</code> generates a locally-trusted certificate for a custom hostname in seconds:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkcert</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -install</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkcert</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">your-host-ip-or-domai</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">n</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><p>Set <code>SSL_CERT_FILE</code> so the E2B SDK trusts the generated CA:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> SSL_CERT_FILE</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/root/.local/share/mkcert/rootCA.pem</span></span></code></pre></div><blockquote><p>mkcert certificates are only trusted on machines where <code>mkcert -install</code> has been run. Not suitable for production or shared deployments.</p></blockquote><h3 id="option-b-—-your-own-certificate-domain-production" tabindex="-1">Option B — Your Own Certificate / Domain (Production) <a class="header-anchor" href="#option-b-—-your-own-certificate-domain-production" aria-label="Permalink to &quot;Option B — Your Own Certificate / Domain (Production)&quot;">​</a></h3><p>Edit CubeProxy&#39;s <code>nginx.conf</code> to use your certificate and private key:</p><div class="language-nginx vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">nginx</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">server</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> {</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    listen </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">443</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ssl;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    server_name </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">your.domain.com;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    ssl_certificate </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    /path/to/your/cert.pem;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    ssl_certificate_key </span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">/path/to/your/key.pem;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>Also pass <code>--sandbox-domain</code> to the Cube API Server to publish the correct domain in API responses (see the &quot;Production: Custom Domain&quot; section above).</p><h3 id="option-c-—-https-only-disable-http" tabindex="-1">Option C — HTTPS-Only (Disable HTTP) <a class="header-anchor" href="#option-c-—-https-only-disable-http" aria-label="Permalink to &quot;Option C — HTTPS-Only (Disable HTTP)&quot;">​</a></h3><p>By default, CubeProxy listens on both HTTP and HTTPS. To disable the HTTP port entirely, remove the HTTP server block from CubeProxy&#39;s <code>nginx.conf</code> and drop the corresponding port mapping in <code>docker-compose.yaml</code>.</p><blockquote><p>The E2B SDK only uses HTTPS, so disabling HTTP has no impact on SDK-based clients.</p></blockquote><hr><h2 id="dev-only-alternative-e2b-dev-sidecar" tabindex="-1">Dev-Only Alternative: e2b-dev-sidecar <a class="header-anchor" href="#dev-only-alternative-e2b-dev-sidecar" aria-label="Permalink to &quot;Dev-Only Alternative: e2b-dev-sidecar&quot;">​</a></h2><p>If you are experimenting with Cube in a local development environment and want to skip both wildcard DNS setup and self-signed certificate trust issues, the <strong>e2b-dev-sidecar</strong> approach is the easiest option.</p><p>It starts a lightweight local proxy that intercepts E2B SDK data-plane requests and rewrites the <code>Host</code> header before forwarding them to CubeProxy. This means:</p><ul><li><strong>No wildcard DNS needed</strong>: no <code>*.cube.app</code> record required on the developer machine</li><li><strong>No certificate trust needed</strong>: the sidecar skips server certificate verification by default (<code>CUBE_REMOTE_PROXY_VERIFY_SSL=false</code>)</li></ul><p>See: <a href="https://github.com/tencentcloud/CubeSandbox/tree/master/examples/e2b-dev-sidecar" target="_blank" rel="noreferrer">e2b-dev-sidecar example</a></p><blockquote><p><strong>Note:</strong> e2b-dev-sidecar is a minimal dev-only implementation and is not intended for production use.</p></blockquote>`,45)])])}const k=a(o,[["render",n]]);export{u as __pageData,k as default};
